const config = JSON.parse($json.mc_config || '{}');
const apiKey = config.api_key || '';
const dc = apiKey.split('-').pop() || 'us1';
const listId = config.list_id || '';

return {
  json: {
    tenant_id: $json.tenant_id,
    api_key: apiKey,
    dc: dc,
    list_id: listId,
    lists_url: `https://${dc}.api.mailchimp.com/3.0/lists/${listId}`,
    campaigns_url: `https://${dc}.api.mailchimp.com/3.0/campaigns?count=10&sort_field=send_time&sort_dir=DESC`
  }
};

const campaigns = $json.campaigns || [];
const tenantId = $('Prepare Mailchimp URLs').item.json.tenant_id;

return campaigns.map(c => ({
  json: {
    tenant_id: tenantId,
    date: c.send_time?.split('T')[0] || new Date().toISOString().split('T')[0],
    campaign_name: c.settings?.subject_line || c.settings?.title || 'Unknown',
    campaign_id: c.id,
    subscribers: c.emails_sent || 0,
    open_rate: c.report_summary?.open_rate || 0,
    click_rate: c.report_summary?.click_rate || 0,
    revenue: c.report_summary?.ecommerce?.total_revenue || 0,
    new_subs: 0
  }
}));
